Javascript.validate:
var val = Services.getValue(AmntOfCharge.dataBinding);
var err = WPU.validateCurrency(val);
if( null == err )
{	Services.setValue(AmntOfCharge.dataBinding, WPU.formatToTwoDP(val));
}
return err;

Javascript.miscCode:
function DefaultCurrency519() {}
DefaultCurrency519.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency519.tabIndex = -1;
DefaultCurrency519.maxLength = 1;
DefaultCurrency519.isReadOnly = function(){return true;}
DefaultCurrency519.isTemporary = function(){return true;}
DefaultCurrency519.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency519.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

Context.validate:
var val = Services.getValue(AmntOfCharge.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err)
{	Services.setValue(AmntOfCharge.dataBinding, WPU.formatToTwoDP(val));
}
return err;
